import React, { useMemo, useState, useEffect, useCallback } from 'react';
import { useTable, useSortBy, usePagination } from 'react-table';
import './PurchaseFunc.css';

const Stocks = ({ apiBaseUrl }) => {
  const [materials, setMaterials] = useState([]);
  const [purchases, setPurchases] = useState([]);
  const [locations, setLocations] = useState([]);
  const [outflows, setOutflows] = useState([]);
  const [selectedLocation, setSelectedLocation] = useState('');
  const [stock, setStock] = useState([]);
  const [globalFilterOne, setGlobalFilterOne] = useState('');
  const [globalFilterTwo, setGlobalFilterTwo] = useState('');

  const fetchAPI = useCallback(async (url, options = {}) => {
    const authToken = sessionStorage.getItem('authToken');
    const response = await fetch(url, {
      ...options,
      headers: {
        ...options.headers,
        Authorization: `Bearer ${authToken}`,
      },
    });
    if (!response.ok) {
      const errorResponse = await response.json();
      throw new Error(errorResponse.message || `Error fetching ${url}`);
    }
    return response.json();
  }, []);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const [materialResponse, purchaseResponse, locationResponse, outflowsResponse] = await Promise.all([
          fetchAPI(`${apiBaseUrl}/materiallist`),
          fetchAPI(`${apiBaseUrl}/PurchasesAPI`),
          fetchAPI(`${apiBaseUrl}/LocationsAPI`),
          fetchAPI(`${apiBaseUrl}/outflowsAPI`),
        ]);

        // Filter and process stock based on conditions
        const processedStock = purchaseResponse.filter((purchase) => {
          if (purchase.location === parseInt(selectedLocation, 10)) {
            if (!purchase.width) {
              // Ensure unique materialid when width is undefined
              return !stock.some((item) => item.materialid === purchase.materialid);
            }
            // Include all entries if width exists
            return true;
          }
          return false;
        });

        setMaterials(materialResponse);
        setPurchases(purchaseResponse);
        setLocations(locationResponse);
        setOutflows(outflowsResponse);
        setStock(processedStock);
      } catch (error) {
        console.error('Error fetching data:', error);
      }
    };
    fetchData();
  }, [apiBaseUrl, fetchAPI, selectedLocation]);

  const filteredData = useMemo(() => {
    if (!selectedLocation) return [];
    return stock.filter((row) => {
      const material = materials.find((m) => m.matid === row.materialid);
      const materialName = material ? material.name.toLowerCase() : '';
      const rowString = Object.values(row)
        .map((val) => String(val).toLowerCase())
        .join(' ') + ' ' + materialName;
      return (
        row.location === parseInt(selectedLocation, 10) &&
        rowString.includes(globalFilterOne.toLowerCase()) &&
        rowString.includes(globalFilterTwo.toLowerCase())
      );
    });
  }, [stock, globalFilterOne, globalFilterTwo, materials, selectedLocation]);

  const calculateTotalCost = useCallback(
    (materialId, location, lotNumber) => {
      let totalCost = 0;

      // Calculate cost from purchases
      const filteredPurchases = purchases.filter(
        (purchase) => purchase.materialid === materialId && purchase.location === location && purchase.lotnumber === lotNumber
      );
      filteredPurchases.forEach((purchase) => {
        totalCost += parseFloat(purchase.quantity) * parseFloat(purchase.price);
      });

      // Calculate cost reduction from outflows using FIFO
      let remainingOutflow = outflows
        .filter((outflow) => outflow.materialid === materialId && outflow.location === location && outflow.lotnumber === lotNumber)
        .reduce((total, outflow) => total + parseFloat(outflow.quantity), 0);

      for (const purchase of filteredPurchases) {
        if (remainingOutflow <= 0) break;
        const availableQuantity = parseFloat(purchase.quantity);
        const usedQuantity = Math.min(availableQuantity, remainingOutflow);
        totalCost -= usedQuantity * parseFloat(purchase.price);
        remainingOutflow -= usedQuantity;
      }

      return totalCost.toFixed(2);
    },
    [purchases, outflows]
  );

  const totalCostOfStock = useMemo(() => {
    return filteredData.reduce((sum, row) => {
      const location = parseInt(selectedLocation, 10);
      const cost = parseFloat(calculateTotalCost(row.materialid, location, row.lotnumber) || 0);
      return sum + cost;
    }, 0).toFixed(2);
  }, [filteredData, calculateTotalCost, selectedLocation]);

  const columns = useMemo(
    () => [
      { Header: 'ID', accessor: 'id' },
      { Header: 'Material ID', accessor: 'materialid' },
      {
        Header: 'Material Name',
        accessor: (row) => {
          const material = materials.find((material) => material.matid === row.materialid);
          return material ? material.name : 'Material not found';
        },
      },
      {
        Header: 'Material Field',
        accessor: (row) => {
          const material = materials.find((material) => material.matid === row.materialid);
          return material ? material.field || 'Unknown' : 'N/A';
        },
      },
      { Header: 'Width', accessor: 'width' },
      { Header: 'Lot No', accessor: 'lotnumber' },
      {
        Header: 'Quantity',
        accessor: (row) => {
          const location = parseInt(selectedLocation, 10);
          if (!location) return 'N/A';

          const filteredPurchases = purchases.filter(
            (purchase) => purchase.materialid === row.materialid && purchase.lotnumber === row.lotnumber && purchase.location === location
          );
          const filteredOutflows = outflows.filter(
            (outflow) => outflow.materialid === row.materialid && outflow.lotnumber === row.lotnumber && outflow.location === location
          );

          const totalPurchases = filteredPurchases.reduce((sum, purchase) => sum + parseFloat(purchase.quantity), 0);
          const totalOutflows = filteredOutflows.reduce((sum, outflow) => sum + parseFloat(outflow.quantity), 0);

          return (totalPurchases - totalOutflows).toFixed(2);
        },
      },
      {
        Header: 'Average Cost',
        accessor: (row) => {
          const location = parseInt(selectedLocation, 10);
          if (!location) return 'N/A';

          const totalCost = calculateTotalCost(row.materialid, location, row.lotnumber);
          return `${totalCost} €`;
        },
      },
    ],
    [materials, calculateTotalCost, outflows, purchases, selectedLocation]
  );

  const {
    getTableProps,
    getTableBodyProps,
    headerGroups,
    page,
    prepareRow,
    state: { pageIndex, pageSize },
    gotoPage,
    nextPage,
    previousPage,
    canNextPage,
    canPreviousPage,
    setPageSize,
    pageCount,
  } = useTable(
    {
      columns,
      data: filteredData,
      initialState: { pageIndex: 0, pageSize: 10 },
    },
    useSortBy,
    usePagination
  );

  return (
    <div className="container">
      <div className="form-group">
        <label>Location:</label>
        <select value={selectedLocation} onChange={(e) => setSelectedLocation(e.target.value)}>
          <option value="">Select a location</option>
          {locations.map((location) => (
            <option key={location.id} value={location.id}>
              {location.locationname}
            </option>
          ))}
        </select>
      </div>

      <div className="search">
        <input value={globalFilterOne} onChange={(e) => setGlobalFilterOne(e.target.value)} placeholder="Global Filter 1" />
        <input value={globalFilterTwo} onChange={(e) => setGlobalFilterTwo(e.target.value)} placeholder="Global Filter 2" />
      </div>

      <table {...getTableProps()} className="table">
        <thead>
          {headerGroups.map((headerGroup) => (
            <tr {...headerGroup.getHeaderGroupProps()}>
              {headerGroup.headers.map((column) => (
                <th {...column.getHeaderProps(column.getSortByToggleProps())}>
                  {column.render('Header')}
                  <span>{column.isSorted ? (column.isSortedDesc ? ' 🔽' : ' 🔼') : ''}</span>
                </th>
              ))}
            </tr>
          ))}
        </thead>
        <tbody {...getTableBodyProps()}>
          {page.map((row) => {
            prepareRow(row);
            return (
              <tr {...row.getRowProps()}>
                {row.cells.map((cell) => (
                  <td {...cell.getCellProps()}>{cell.render('Cell')}</td>
                ))}
              </tr>
            );
          })}
        </tbody>
      </table>

      <div className="pagination">
        <button onClick={() => previousPage()} disabled={!canPreviousPage}>
          Previous
        </button>
        <span>
          Page {pageIndex + 1} of {pageCount}
        </span>
        <button onClick={() => nextPage()} disabled={!canNextPage}>
          Next
        </button>
        <span>
          | Go to page:{' '}
          <input
            type="number"
            defaultValue={pageIndex + 1}
            onChange={(e) => gotoPage(Number(e.target.value) - 1)}
            style={{ width: '50px' }}
          />
        </span>
        <select value={pageSize} onChange={(e) => setPageSize(Number(e.target.value))}>
          {[10, 25, 50].map((size) => (
            <option key={size} value={size}>
              Show {size}
            </option>
          ))}
        </select>
      </div>

      <div className="total-cost">
        <strong>Total Cost of Stock:</strong> {`${totalCostOfStock} €`}
      </div>
    </div>
  );
};

export default Stocks;
